































import Vue from 'vue'

export default Vue.extend({
	data() {
		return {
			active: false,
		}
	},
	props: {
		icon: {
			type: String,
			required: false,
		},
		link: {
			type: String,
			required: false,
		},
		timeEvents: {
			type: Array as () => TimeEvent[],
			required: true,
		},
		title: {
			type: String,
			required: false,
		},
	},
})
