




















import Vue from 'vue'

export default Vue.extend({
	props: {
		active: {
			type: Boolean,
			required: false,
		},
		image: {
			type: String,
			required: true
		},
		text: {
			type: String,
			required: true
		},
	},
	data() {
		return {
			inview: false,
		}
	},
	methods: {
		visibilityChange(visible: boolean) {
			this.inview = visible
		},
	},
})
